$("[data-copy]").click(function () {
    let text = $(this).attr("data-copy")
    let $tmp = $("<textarea>");
    $("body").append($tmp);
    $tmp.val(text).select();
    document.execCommand("copy");
    $tmp.remove();
})

$("._show-all").click(function () {
    $(this).parents("._show-all-parent").addClass("_open")
})

const wrap = document.querySelector('.profile-menu__items');
if(wrap){
    const active = wrap.querySelector('.profile-menu__item._active');
    if (active) {
        requestAnimationFrame(() => scrollToActive(active));
    }
}

function scrollToActive(el) {
    const wrapRect = wrap.getBoundingClientRect();
    const elRect = el.getBoundingClientRect();
    const offset = elRect.left - wrapRect.left - (wrapRect.width - elRect.width) / 2;
    wrap.scrollBy({ left: offset, behavior: 'smooth' });
}

$(".sort-select select").change(function () {
    $(this).parents(".sort-select").find(".sort-select__current").html(
        $(this).val()
    )
})

$("._toggle-favourite").click(function () {
    $(this).toggleClass("_active")
})

$(".calendar__show").click(function () {
    $(".calendar__hidden").slideToggle()
})
